# Utility module - helper functions and constants
from geometry import Shape

def square(x: float) -> float:
    return x * x

def sum_areas(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

PI: float = 3.14159
